def _resolve_user_identity() -> str:
    """
    Resolve the current user identity through a prioritised chain so the app
    never falls back to UNKNOWN when running locally or on Azure Web App.

    Resolution order:
      1. Streamlit session state  (if already resolved this session)
      2. Fabric / Snowflake SQL   CURRENT_USER() - works inside Fabric runtime
      3. Azure AD token header    X-MS-CLIENT-PRINCIPAL-NAME injected by Azure
                                  Easy Auth / App Service authentication
      4. APP_USER environment variable  - set in Azure App Service configuration
      5. OS login name            getpass.getuser() - works locally on any OS
      6. Machine hostname         last resort, always non-empty
    """
    # ── 1. Session-state cache (avoid DB round-trip on every rerun) ──────────
    cached = st.session_state.get("_resolved_user")
    if cached:
        return cached

    def _cache(val: str) -> str:
        st.session_state["_resolved_user"] = val
        return val

    def _clean(val) -> str:
        if val is None:
            return ""
        s = str(val).strip()
        return "" if s in ("None", "nan", "null", "<NA>", "") else s

    # ── 2. Fabric SQL CURRENT_USER() ─────────────────────────────────────────
    try:
        df = get_session().sql("""
            SELECT COALESCE(
                TRIM(CURRENT_USER()),
                TRIM(SYS_CONTEXT('Fabric$SESSION', 'PRINCIPAL_NAME')),
                ''
            ) AS SF_USER
        """).to_pandas()
        if not df.empty and "SF_USER" in df.columns:
            val = _clean(df.at[0, "SF_USER"])
            if val:
                return _cache(val)
    except Exception:
        pass

    # ── 3. Azure App Service Easy Auth header ────────────────────────────────
    # Azure injects X-MS-CLIENT-PRINCIPAL-NAME when App Service Authentication
    # is enabled (Azure AD / Entra ID login).  Streamlit exposes request headers
    # via st.context.headers (Streamlit >= 1.37) or the legacy _get_websocket_headers.
    try:
        headers = {}
        if hasattr(st, "context") and hasattr(st.context, "headers"):
            headers = dict(st.context.headers)
        elif hasattr(st, "_get_websocket_headers"):
            headers = dict(st._get_websocket_headers() or {})

        for header_name in (
            "X-MS-CLIENT-PRINCIPAL-NAME",
            "x-ms-client-principal-name",
            "X-Forwarded-User",
            "x-forwarded-user",
        ):
            val = _clean(headers.get(header_name, ""))
            if val:
                # Strip domain prefix if present  e.g. CORP\roshan.saxena -> roshan.saxena
                val = val.split("\\")[-1].split("@")[0]
                return _cache(val)
    except Exception:
        pass

    # ── 4. APP_USER environment variable ─────────────────────────────────────
    # Set this in Azure App Service → Configuration → Application settings
    # Name: APP_USER   Value: service-account or team name
    import os as _os
    env_user = _clean(_os.environ.get("APP_USER", ""))
    if env_user:
        return _cache(env_user)

    # ── 5. OS login name (works locally on Windows, Mac, Linux) ─────────────
    try:
        import getpass as _gp
        login = _clean(_gp.getuser())
        if login and login.lower() not in ("unknown", ""):
            return _cache(login)
    except Exception:
        pass

    # ── 6. Machine hostname ───────────────────────────────────────────────────
    try:
        import socket as _sock
        host = _clean(_sock.gethostname().split(".")[0])
        if host:
            return _cache(f"host:{host}")
    except Exception:
        pass

    return _cache("UNKNOWN")


def _get_current_user_raw() -> str:
    """Backward-compatible wrapper around _resolve_user_identity()."""
    return _resolve_user_identity()


