def _append_genie_question(query: str, analysis_type: str):
    q = query.strip()
    if not q:
        return
    norm = _sql_escape(q.lower())
    t = _sql_escape(analysis_type.strip())
    current_user = _get_current_user_raw() or "UNKNOWN"
    user_esc = _sql_escape(current_user)

    try:
        WH = f"[{Config.WAREHOUSE_SCHEMA}].[{Config.HISTORY_TABLE_NAME}]"

        # Check if this question already exists for this user
        check_df = run_warehouse_df(f"""
            SELECT COUNT(*) AS CNT
            FROM   {WH}
            WHERE  NORMALIZED_QUERY = '{norm}'
              AND  USER_NAME        = '{user_esc}'
        """)

        # Column name is always uppercase from Fabric Warehouse
        cnt_val = 0
        if not check_df.empty:
            col = check_df.columns[0]   # take first column regardless of name
            cnt_val = int(check_df.iloc[0][col] or 0)

        if cnt_val > 0:
            run_warehouse_non_query(f"""
                UPDATE {WH}
                SET    FREQUENCY     = FREQUENCY + 1,
                       LAST_ASKED_AT = CONVERT(VARCHAR(30), GETDATE(), 120),
                       TYPE          = '{t}'
                WHERE  NORMALIZED_QUERY = '{norm}'
                  AND  USER_NAME        = '{user_esc}'
            """)
        else:
            run_warehouse_non_query(f"""
                INSERT INTO {WH}
                    (ID, NORMALIZED_QUERY, TYPE, USER_NAME, LAST_ASKED_AT, FREQUENCY)
                VALUES (
                    ABS(CHECKSUM(NEWID())),
                    '{norm}', '{t}', '{user_esc}', CONVERT(VARCHAR(30), GETDATE(), 120), 1
                )
            """)

        if "genie_history_error" in st.session_state:
            st.session_state.genie_history_error = None

    except Exception as e:
        st.session_state.genie_history_error = str(e)


