SAVED_TBL = f"[{Config.WAREHOUSE_SCHEMA}].[{Config.SAVED_INSIGHTS_TABLE}]"

def _save_insight(
    question: str,
    title: str,
    analysis_type: str = "custom",
    page: str = "genie",
):
    """
    Persist a Saved Insight row for the current user into dbo.saved_insights.
    Uses only the columns present in your table:
      QUESTION, TITLE, ANALYSIS_TYPE, CREATED_BY, CREATED_AT (date), PAGE
    """
    import streamlit as st

    q = (question or "").strip()
    t = (title or "").strip()
    if not q:
        st.warning("Nothing to save: question is empty.")
        return

    try:
        current_user = (_get_current_user_raw() or "UNKNOWN").strip()

        # Escape strings for SQL
        user_esc = _sql_escape(current_user)
        q_esc    = _sql_escape(q)
        t_esc    = _sql_escape(t or q[:80])
        a_esc    = _sql_escape((analysis_type or "custom").strip())
        page_esc = _sql_escape((page or "genie").strip())

        sql = f"""
            INSERT INTO {SAVED_TBL}
                (INSIGHT_ID, CREATED_AT, CREATED_BY, PAGE, TITLE, QUESTION, ANALYSIS_TYPE)
            VALUES (
                ABS(CHECKSUM(NEWID())),
                CONVERT(VARCHAR(30), GETDATE(), 120),
                '{user_esc}', '{page_esc}', '{t_esc}', '{q_esc}', '{a_esc}'
            )
        """

        # Execute against Warehouse
        run_warehouse_non_query(sql)

        try:
            st.toast("Insight saved.")
        except Exception:
            pass

        st.session_state.pop("saved_insights_error", None)

    except Exception as e:
        import traceback
        msg = f"Save failed: {e}"
        st.session_state["saved_insights_error"] = msg
        st.error(msg)
        st.caption("Last attempted INSERT:")
        st.code(sql, language="sql")
        st.caption("Traceback:")
        st.code(traceback.format_exc())


def _get_saved_insights_for_user(
    n: int = 20,
    page: str = "genie",
    include_all_pages: bool = False,
):
    """
    Return recent saved insights for the current user, optionally filtered by page.
    Uses columns available in dbo.saved_insights.
    """
    import streamlit as st

    try:
        current_user = (_get_current_user_raw() or "UNKNOWN").strip()
        user_esc = _sql_escape(current_user)
        page_esc = _sql_escape((page or "genie").strip())

        page_predicate = "" if include_all_pages else f"AND PAGE = '{page_esc}'"

        sql = f"""
            SELECT TOP ({int(n)})
                INSIGHT_ID,
                CREATED_AT,
                CREATED_BY,
                PAGE,
                TITLE,
                QUESTION,
                ANALYSIS_TYPE
            FROM {SAVED_TBL}
            WHERE UPPER(RTRIM(LTRIM(COALESCE(CREATED_BY,'UNKNOWN')))) = UPPER('{user_esc}')
              {page_predicate}
            ORDER BY CREATED_AT DESC, INSIGHT_ID DESC;
        """

        df = run_warehouse_df(sql)
        if df is None or df.empty:
            return []

        out = []
        for _, row in df.iterrows():
            out.append({
                "id": row.get("INSIGHT_ID"),
                "title": (row.get("TITLE") or "").strip(),
                "question": (row.get("QUESTION") or "").strip(),
                "created_at": row.get("CREATED_AT"),
                "created_by": (row.get("CREATED_BY") or "").strip(),
                "page": (row.get("PAGE") or "").strip(),
                "analysis_type": (row.get("ANALYSIS_TYPE") or "").strip(),
            })
        st.session_state.pop("saved_insights_error", None)
        return out

    except Exception as e:
        msg = f"Load failed: {e}"
        st.session_state["saved_insights_error"] = msg
        st.error(msg)
        try:
            st.caption("Last attempted SELECT:")
            st.code(sql, language="sql")
        except Exception:
            pass
        return []

GENIE_HISTORY_TABLE = f"[{DB}].[{SCHEMA}].[genie_question_history]"

def _get_frequent_questions(n: int = 10):
    """Top n questions by total frequency across all users. Groups by normalized_query."""
    try:
        WH_TBL = f"[{Config.WAREHOUSE_SCHEMA}].[{Config.HISTORY_TABLE_NAME}]"
        sql = f"""
            SELECT TOP ({int(n)})
                UPPER(LTRIM(RTRIM(NORMALIZED_QUERY))) AS NORMALIZED_QUERY,
                SUM(COALESCE(FREQUENCY, 0))           AS CNT
            FROM   {WH_TBL}
            WHERE  COALESCE(LTRIM(RTRIM(NORMALIZED_QUERY)), '') <> ''
            GROUP  BY UPPER(LTRIM(RTRIM(NORMALIZED_QUERY)))
            ORDER  BY CNT DESC, NORMALIZED_QUERY ASC;
        """
        df = run_warehouse_df(sql)
        if df is None or df.empty:
            return []
        return [
            {"query": (str(row.get("NORMALIZED_QUERY") or "")).strip(),
             "count": int(row.get("CNT") or 0)}
            for _, row in df.iterrows()
        ]
    except Exception as e:
        # Optional: surface the SQL to debug quickly
        try:
            import streamlit as st
            st.error(f"Load frequent questions failed: {e}")
            st.code(sql, language="sql")
        except Exception:
            pass
        return []

