def _get_frequent_questions_by_user(n: int = 10):
    """Top n questions by frequency for the current user only."""
    try:
        current_user = _get_current_user_raw() or "UNKNOWN"
        user_esc = _sql_escape(current_user)
        WH_TBL = f"[{Config.WAREHOUSE_SCHEMA}].[{Config.HISTORY_TABLE_NAME}]"
        df = run_warehouse_df(f"""
            SELECT TOP ({int(n)})
                NORMALIZED_QUERY,
                FREQUENCY AS CNT
            FROM   {WH_TBL}
            WHERE  USER_NAME        = '{user_esc}'
              AND  NORMALIZED_QUERY <> ''
            ORDER  BY FREQUENCY DESC
        """)
        if df is None or df.empty:
            return []
        return [
            {"query": (str(row.get("NORMALIZED_QUERY") or "")).strip(),
             "count": int(row.get("CNT") or 0)}
            for _, row in df.iterrows()
        ]
    except Exception:
        return []


# ========== Utilities ==========

def compute_range_preset(preset: str):
    today = date.today()
    if preset == "Last 30 Days":
        return today - timedelta(days=30), today
    if preset == "QTD":
        start = date(today.year, ((today.month - 1)//3)*3 + 1, 1)
        return start, today
    if preset == "YTD":
        return date(today.year, 1, 1), today
    return today.replace(day=1), today  # Current month

def sql_date(d: date) -> str:
    return f"'{d.strftime('%Y-%m-%d')}'"

@st.cache_data(ttl=300, show_spinner=False)
def run_df(sql: str) -> pd.DataFrame:
    """Execute SQL and return a DataFrame. Results are cached for 5 minutes (ttl=300)."""
    try:
        _sess = get_session()
        if not _sess:
            return pd.DataFrame()
        return _sess.sql(sql).to_pandas()
    except Exception as e:
        st.warning(f"Query failed: {e}\nSQL: {sql}")
        return pd.DataFrame()

def safe_number(val, default=0.0):
    try:
        if val is None or (isinstance(val, float) and math.isnan(val)):
            return default
        return float(val)
    except Exception:
        return default

def safe_int(val, default=0):
    try:
        if val is None or (isinstance(val, float) and math.isnan(val)):
            return default
        return int(float(val))
    except Exception:
        return default

# Cortex Complete model for prescriptive analysis (fallback: rule-based if unavailable)
# Azure OpenAI model for prescriptive analysis
