    cur_spend = get_num(kpi_cur, 'TOTAL_SPEND', 0)
    cur_vend  = get_num(kpi_cur, 'ACTIVE_VENDORS', 0)
    cur_pend  = get_num(kpi_cur, 'PENDING_INV', 0)

    prev_pos   = get_num(kpi_prev, 'ACTIVE_POS', 0)
