    def call_cortex_analyst(query_text: str):
        """Call Azure OpenAI to generate SQL and insights (replacing Fabric Cortex Analyst)."""

        def _is_valid_sql(text: str) -> bool:
            """Return True only if text is a genuine SELECT statement."""
            cleaned = text.strip().lstrip(";").strip()
            # Strip markdown fences the model sometimes leaves
            if cleaned.startswith("```"):
                cleaned = re.sub(r"^```[a-zA-Z]*\n?", "", cleaned, flags=re.IGNORECASE)
                cleaned = cleaned.rstrip("`").strip()
            return cleaned.upper().startswith("SELECT") or cleaned.upper().startswith("WITH")

        def _clean_sql(text: str) -> str:
            """Strip markdown fences and leading/trailing whitespace."""
            s = text.strip()
            s = re.sub(r"^```[a-zA-Z]*\n?", "", s, flags=re.IGNORECASE)
            s = s.rstrip("`").strip()
            return s

        try:
            # Step 1: Build a strict analytical prompt that forces SQL output
            analytical_hint = f"""{DECISION_SUPPORT_INSTRUCTION}

            USER QUESTION: {query_text}

            IMPORTANT: You must return ONLY a valid T-SQL SELECT query.
            Do NOT return explanations, prose, bullet points, or anything other than SQL.
            If the question is conversational or unclear, return:
            SELECT 'Please ask a specific procurement question about invoices, vendors, spend, or payments.' AS MESSAGE

            SQL query only:"""

            sql_query = generate_sql(analytical_hint)
            sql_query = _clean_sql(sql_query)

            # Step 2: Validate it is actually SQL before executing
            if not _is_valid_sql(sql_query):
                # AI returned prose - extract any SQL block if present, else ask user to clarify
                sql_match = re.search(
                    r"(WITH\s+\w|SELECT\s+)", sql_query, re.IGNORECASE
                )
                if sql_match:
                    sql_query = sql_query[sql_match.start():].strip()
                else:
                    return {
                        "message": {
                            "content": [{
                                "type": "text",
                                "text": (
                                    "Please ask a specific procurement question. For example:\n"
                                    "- What is the total spend by vendor this month?\n"
                                    "- Show overdue invoices over $10,000\n"
                                    "- Which vendors have the highest payment delays?"
                                )
                            }]
                        }
                    }

            # Step 3: Execute SQL on Fabric
            try:
                df = run_df(sql_query)
            except Exception as sql_err:
                return {"error": f"SQL execution failed: {str(sql_err)}"}
            
            # Step 3: Build response in Cortex Analyst format
            response = {
                "message": {
                    "content": [
                        {
                            "type": "sql",
                            "statement": sql_query
                        }
                    ]
                }
            }
            
            # Step 4: Generate descriptive + prescriptive insights from the data
            data_summary = f"""
            Query: {query_text}
            Rows returned: {len(df)}

            Data (first 10 rows):
            {df.head(10).to_string(index=False, max_colwidth=50) if not df.empty else 'No data'}
            """
                    
                    # Call AI to generate BOTH descriptive and prescriptive
            combined_prompt = f"""You are a procurement analytics expert. The user asked: "{query_text}"

            Here is the data that answers their question:
            {data_summary}

            Provide your response in this EXACT format:

            **Descriptive**: [State what the data shows - include specific numbers, percentages, and directly answer the question]

            **Prescriptive**: [List 3-5 specific, actionable recommendations based on the findings. Each recommendation should include concrete next steps.]

          Rules:
            - Be specific with numbers from the data
            - For yes/no questions, start Descriptive with "Yes" or "No"
            - Do NOT use vague phrases like "review the data"
            - Include vendor names, amounts, and percentages where relevant
            - Use **bold** for all key numbers, amounts, percentages e.g. **$30.98M**, **94%**, **441 days**
            - Do NOT use HTML tags like <strong> — only use ** for bold
    """
            
            insights = cortex_complete(combined_prompt, temperature=0.3)
            
            if insights:
                response["message"]["content"].append({
                    "type": "text",
                    "text": insights  #  CORRECT - uses "text"
                })
            
            return response
            
        except Exception as e:
            return {"error": str(e)}
    
    def process_genie_query(query: str, analysis_type: str = "custom"):
        """Process a query, store response in recent analyses, return response."""
        # Add user message
        st.session_state.genie_messages.append({
            "role": "user",
            "content": query,
            "timestamp": pd.Timestamp.now()
        })
        
        # Call Cortex Analyst
        response = call_cortex_analyst(query)
        
        # Add to recent analyses (include response so we can restore when clicked)
        st.session_state.recent_analyses.insert(0, {
            "query": query,
            "type": analysis_type,
            "timestamp": pd.Timestamp.now(),
            "response": response,
        })
        # Keep only last 10
        st.session_state.recent_analyses = st.session_state.recent_analyses[:10]
        # Persist question for all-sessions recent & FAQ (not session-specific)
        _append_genie_question(query, analysis_type)
        
        #CACHE THE RESULT - Save to QUERY_RESULT_CACHE warehouse table
        try:
            from db_service import cache_set
            if isinstance(response, dict) and 'message' in response:
                # Extract SQL from response structure
                result_sql = ''
                try:
                    content = response.get('message', {}).get('content', [])
                    if content and isinstance(content, list):
                        # First item should be the SQL statement
                        for item in content:
                            if isinstance(item, dict) and item.get('type') == 'sql':
                                result_sql = item.get('statement', '')
                                break
                except Exception:
                    pass
                
                # Re-execute the query to get the dataframe for caching
                if result_sql:
                    try:
                        result_df = run_df(result_sql)
                        cache_set(
                            question=query,
                            sql=result_sql,
                            result_df=result_df
                        )
                        logger.info(f"✓ Cached result for: {query[:60]}")
                    except Exception as cache_error:
                        logger.warning(f"Could not cache results: {cache_error}")
        except Exception as outer_error:
            logger.warning(f"Cache operation failed: {outer_error}")

        return response

